(function(){
  const {computed,createApp,reactive,ref}=Vue;
  const schema=window.SNOWY_PROTOTYPE_SCHEMA;
  const app=createApp({
    setup(){
      const activeId=ref(schema.pages[0].id),visited=ref([schema.pages[0].id]),query=reactive({}),rowsByPage=reactive(Object.fromEntries(schema.pages.map(page=>[page.id,JSON.parse(JSON.stringify(page.rows))]))),selectedKeys=ref([]),detailOpen=ref(false),detailRecord=ref(null),formOpen=ref(false),formMode=ref('add'),formModel=ref({}),importOpen=ref(false);
      const activePage=computed(()=>schema.pages.find(page=>page.id===activeId.value)||schema.pages[0]);
      const menuGroups=computed(()=>{const groups={};for(const page of schema.pages){const root=page.menuPath[0]||'业务功能';(groups[root]||(groups[root]=[])).push(page)}return groups});
      const filteredRows=computed(()=>rowsByPage[activeId.value].filter(row=>activePage.value.queryFields.every(field=>{const value=query[field.key];if(value==null||value===''||(Array.isArray(value)&&!value.length))return true;if(Array.isArray(value))return true;return String(row[field.key]??'').includes(String(value))})));
      function switchPage(id){activeId.value=id;if(!visited.value.includes(id))visited.value.push(id);Object.keys(query).forEach(key=>delete query[key]);selectedKeys.value=[]}
      function replaceQuery(value){Object.keys(query).forEach(key=>delete query[key]);Object.assign(query,value||{})}
      function reset(){Object.keys(query).forEach(key=>delete query[key]);antd.message.success('查询条件已重置')}
      function search(){antd.message.success(`查询完成，共 ${filteredRows.value.length} 条`)}
      function openDetail(record){detailRecord.value=record;detailOpen.value=true}
      function openForm(mode,record={}){formMode.value=mode;formModel.value={...record};detailRecord.value=record;formOpen.value=true}
      function saveForm(){const page=activePage.value;if(formMode.value==='add'){const next={id:Date.now(),...formModel.value};rowsByPage[page.id].unshift(next)}else{const target=rowsByPage[page.id].find(row=>row.id===formModel.value.id);if(target)Object.assign(target,formModel.value)}formOpen.value=false;antd.message.success(formMode.value==='add'?'新增成功':'保存成功')}
      function remove(record){antd.Modal.confirm({title:'删除确认',content:`确定删除“${record.title||record.name||record.id}”吗？`,okText:'删除',okButtonProps:{danger:true},onOk:()=>{const rows=rowsByPage[activeId.value],index=rows.findIndex(row=>row.id===record.id);if(index>=0)rows.splice(index,1);antd.message.success('删除成功')}})}
      function batchDelete(){if(!selectedKeys.value.length)return;antd.Modal.confirm({title:'批量删除确认',content:`确定删除选中的 ${selectedKeys.value.length} 条数据吗？`,okText:'删除',okButtonProps:{danger:true},onOk:()=>{rowsByPage[activeId.value]=rowsByPage[activeId.value].filter(row=>!selectedKeys.value.includes(row.id));selectedKeys.value=[];antd.message.success('批量删除成功')}})}
      function toolbarAction(action){if(action.key==='add')openForm('add');else if(action.key==='batchDelete')batchDelete();else if(action.key==='import')importOpen.value=true;else antd.message.success(action.label+'已完成')}
      function rowAction(action,record){if(action.key==='detail')openDetail(record);else if(action.key==='edit')openForm('edit',record);else if(action.key==='delete')remove(record);else antd.message.success(action.label+'已完成')}
      function changeStatus(key,value,record){record[key]=value;antd.message.success(value?'已开启':'已关闭')}
      function confirmImport(){importOpen.value=false;antd.message.success('导入完成')}
      return{schema,activeId,activePage,visited,menuGroups,query,filteredRows,selectedKeys,detailOpen,detailRecord,formOpen,formMode,formModel,importOpen,switchPage,replaceQuery,reset,search,toolbarAction,rowAction,changeStatus,saveForm,confirmImport};
    },
    template:`<snowy-shell><aside class="snowy-sider"><div class="snowy-brand"><div class="snowy-brand-mark">{{schema.system.logoText}}</div><span>{{schema.system.name}}</span></div><div v-for="(pages,group) in menuGroups" :key="group" class="snowy-menu-group"><div class="snowy-menu-title">{{group}}</div><button v-for="page in pages" :key="page.id" class="snowy-menu-item" :class="{active:page.id===activeId}" @click="switchPage(page.id)">{{page.menuPath.slice(1).join(' / ')}}</button></div></aside><main class="snowy-main"><header class="snowy-header"><div class="snowy-header-left"><span>☰</span><span class="snowy-breadcrumb">首页 / {{activePage.menuPath.join(' / ')}}</span></div><div class="snowy-header-right"><a-avatar style="background:#1677ff">管</a-avatar><span>管理员</span></div></header><nav class="snowy-tabs-row"><button v-for="id in visited" :key="id" class="snowy-tab" :class="{active:id===activeId}" @click="switchPage(id)">{{schema.pages.find(page=>page.id===id).title}}</button></nav><section class="snowy-content"><h1 class="snowy-page-title">{{activePage.title}}</h1><snowy-query-form v-if="activePage.queryFields.length" :model-value="query" :fields="activePage.queryFields" :page-id="activePage.id" @update:model-value="replaceQuery" @search="search" @reset="reset"/><div class="snowy-table-card"><snowy-page-toolbar :actions="activePage.toolbarActions" :page-id="activePage.id" :selected-count="selectedKeys.length" @action="toolbarAction"><template #tools><a-button title="刷新" @click="search">↻</a-button><a-button title="表格密度">≡</a-button></template></snowy-page-toolbar><snowy-data-table v-model:selected-keys="selectedKeys" :page="activePage" :rows="filteredRows" @action="rowAction" @status="changeStatus"/></div></section><snowy-detail-drawer v-model:open="detailOpen" :page="activePage" :record="detailRecord"/><snowy-form-drawer v-model:open="formOpen" v-model="formModel" :page="activePage" :mode="formMode" @save="saveForm"/><snowy-import-modal v-model:open="importOpen" @confirm="confirmImport"/><snowy-annotation-layer :page="activePage"/></main></snowy-shell>`
  });
  const components=window.SnowyPrototypeKit.createSnowyComponents(Vue,antd);
  const componentTags={SnowyShell:'snowy-shell',QueryForm:'snowy-query-form',PageToolbar:'snowy-page-toolbar',DataTable:'snowy-data-table',FormDrawer:'snowy-form-drawer',DetailDrawer:'snowy-detail-drawer',ImportModal:'snowy-import-modal',FieldDisplay:'snowy-field-display',FieldEditor:'snowy-field-editor'};
  for(const [name,component] of Object.entries(components))app.component(componentTags[name]||name.replace(/([a-z0-9])([A-Z])/g,'$1-$2').toLowerCase(),component);
  app.component('snowy-annotation-layer',window.SnowyPrototypeKit.createSnowyAnnotationComponent(Vue,antd,dayjs));
  app.use(antd);app.mount('#app');
})();
